changeSet.sql:
-- Pre-flight: delete orphan topic_assignments (doc_id not in catalog_documents for same tenant) DELETE FROM nexus.topic_assignments ta WHERE NOT EXISTS ( SELECT 1 FROM nexus.catalog_documents cd WHERE cd.tenant_id = ta.tenant_id AND cd.tumbler = ta.doc_id );
-- Supporting index: composite (tenant_id, doc_id) for FK lookup performance CREATE INDEX IF NOT EXISTS idx_ta_tenant_doc_id_fk ON nexus.topic_assignments (tenant_id, doc_id);
-- Add composite FK: (tenant_id, doc_id) → catalog_documents(tenant_id, tumbler) ALTER TABLE nexus.topic_assignments ADD CONSTRAINT fk_ta_catalog_doc FOREIGN KEY (tenant_id, doc_id) REFERENCES nexus.catalog_documents (tenant_id, tumbler) ON DELETE CASCADE;

-- Step 1: empty-string sentinel → NULL
UPDATE nexus.document_aspects SET doc_id = NULL WHERE doc_id = '';

-- Step 2: orphan non-null doc_ids → NULL (avoids FK failure on ADD CONSTRAINT)
UPDATE nexus.document_aspects da
SET doc_id = NULL
WHERE da.doc_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM nexus.catalog_documents cd
    WHERE cd.tenant_id = da.tenant_id
      AND cd.tumbler   = da.doc_id
  );

-- Step 3: make column nullable (drop DEFAULT first, then NOT NULL)
ALTER TABLE nexus.document_aspects ALTER COLUMN doc_id DROP DEFAULT;
ALTER TABLE nexus.document_aspects ALTER COLUMN doc_id DROP NOT NULL;

-- Step 4: drop the old partial index (it filtered WHERE doc_id != ''; rebuild as IS NOT NULL)
DROP INDEX IF EXISTS nexus.idx_doc_aspects_doc_id;
CREATE INDEX idx_doc_aspects_doc_id
    ON nexus.document_aspects (tenant_id, doc_id)
    WHERE doc_id IS NOT NULL;

-- Step 5: add composite FK
ALTER TABLE nexus.document_aspects
    ADD CONSTRAINT fk_doc_aspects_catalog_doc
    FOREIGN KEY (tenant_id, doc_id)
    REFERENCES nexus.catalog_documents (tenant_id, tumbler)
    ON DELETE CASCADE;

changeSet.rollback:
ALTER TABLE nexus.document_aspects DROP CONSTRAINT IF EXISTS fk_doc_aspects_catalog_doc;
DROP INDEX IF EXISTS nexus.idx_doc_aspects_doc_id;
CREATE INDEX idx_doc_aspects_doc_id ON nexus.document_aspects (tenant_id, doc_id) WHERE doc_id IS NOT NULL;
ALTER TABLE nexus.document_aspects ALTER COLUMN doc_id SET DEFAULT '';
UPDATE nexus.document_aspects SET doc_id = '' WHERE doc_id IS NULL;
ALTER TABLE nexus.document_aspects ALTER COLUMN doc_id SET NOT NULL;

changeSet.sql:
-- Pre-flight: delete orphan document_highlights rows DELETE FROM nexus.document_highlights dh WHERE NOT EXISTS ( SELECT 1 FROM nexus.catalog_documents cd WHERE cd.tenant_id = dh.tenant_id AND cd.tumbler = dh.doc_id );
-- Supporting index: (tenant_id, doc_id) for FK lookup performance -- (already exists via the UNIQUE constraint, but ensure a plain index for FK scans) CREATE INDEX IF NOT EXISTS idx_doc_highlights_doc_id_fk ON nexus.document_highlights (tenant_id, doc_id);
-- Add composite FK ALTER TABLE nexus.document_highlights ADD CONSTRAINT fk_doc_highlights_catalog_doc FOREIGN KEY (tenant_id, doc_id) REFERENCES nexus.catalog_documents (tenant_id, tumbler) ON DELETE CASCADE;

-- Step 1: empty-string sentinel → NULL
UPDATE nexus.aspect_extraction_queue SET doc_id = NULL WHERE doc_id = '';

-- Step 2: orphan non-null doc_ids → delete rows (doc_id not in catalog_documents for same tenant).
-- DELETE rather than NULL because the FK is CASCADE: orphan rows should be treated as if their
-- parent doc were deleted now (the FK migration matches that semantic retroactively).
DELETE FROM nexus.aspect_extraction_queue aq
WHERE aq.doc_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM nexus.catalog_documents cd
    WHERE cd.tenant_id = aq.tenant_id
      AND cd.tumbler   = aq.doc_id
  );

-- Step 3: make column nullable (doc_id=NULL means "not yet resolved"; still queue-valid)
ALTER TABLE nexus.aspect_extraction_queue ALTER COLUMN doc_id DROP DEFAULT;
ALTER TABLE nexus.aspect_extraction_queue ALTER COLUMN doc_id DROP NOT NULL;

-- Step 4: rebuild index with IS NOT NULL filter (was WHERE doc_id != '')
DROP INDEX IF EXISTS nexus.idx_aspect_queue_doc_id;
CREATE INDEX idx_aspect_queue_doc_id
    ON nexus.aspect_extraction_queue (tenant_id, doc_id)
    WHERE doc_id IS NOT NULL;

-- Step 5: add composite FK with CASCADE on delete
ALTER TABLE nexus.aspect_extraction_queue
    ADD CONSTRAINT fk_aspect_queue_catalog_doc
    FOREIGN KEY (tenant_id, doc_id)
    REFERENCES nexus.catalog_documents (tenant_id, tumbler)
    ON DELETE CASCADE;

changeSet.rollback:
ALTER TABLE nexus.aspect_extraction_queue DROP CONSTRAINT IF EXISTS fk_aspect_queue_catalog_doc;
DROP INDEX IF EXISTS nexus.idx_aspect_queue_doc_id;
CREATE INDEX idx_aspect_queue_doc_id ON nexus.aspect_extraction_queue (tenant_id, doc_id) WHERE doc_id IS NOT NULL;
ALTER TABLE nexus.aspect_extraction_queue ALTER COLUMN doc_id SET DEFAULT '';
UPDATE nexus.aspect_extraction_queue SET doc_id = '' WHERE doc_id IS NULL;
ALTER TABLE nexus.aspect_extraction_queue ALTER COLUMN doc_id SET NOT NULL;
